package pablo.framework;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.graphics.GL20;
import com.badlogic.gdx.scenes.scene2d.Stage;
import com.badlogic.gdx.Screen;
import com.badlogic.gdx.InputProcessor;
import com.badlogic.gdx.InputMultiplexer;
import com.badlogic.gdx.scenes.scene2d.ui.Table;
import com.badlogic.gdx.utils.viewport.*;
import com.badlogic.gdx.utils.viewport.ScreenViewport;

import com.badlogic.gdx.scenes.scene2d.Event;
import com.badlogic.gdx.scenes.scene2d.InputEvent;
import com.badlogic.gdx.scenes.scene2d.InputEvent.Type;

public abstract class BaseScreen implements Screen, InputProcessor
{
    // Dimensioni di riferimento del mondo di gioco
    private static final int WORLD_WIDTH  = 800;
    private static final int WORLD_HEIGHT = 640;

    protected Stage mainStage;
    protected Stage uiStage;
    protected Table uiTable;

    public BaseScreen()
    {
        // StretchViewport: riempie lo schermo senza bande nere (deforma l'aspect ratio).
        mainStage = new Stage( new StretchViewport(WORLD_WIDTH, WORLD_HEIGHT) );

        // ScreenViewport: 1 unità = 1 pixel reale.
        // Corretto per la UI — i bottoni e i font si posizionano in coordinate schermo reali.
        uiStage = new Stage( new ScreenViewport() );

        uiTable = new Table();
        uiTable.setFillParent(true);
        uiStage.addActor(uiTable);

        initialize();
    }

    public abstract void initialize();
    public abstract void update(float dt);

    public void render(float dt)
    {
        dt = Math.min(dt, 1 / 30f);

        mainStage.getViewport().apply();
        uiStage.getViewport().apply();

        uiStage.act(dt);
        mainStage.act(dt);

        update(dt);

        Gdx.gl.glClearColor(0, 0, 0, 1);
        Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

        mainStage.draw();
        uiStage.draw();
    }

    // Propaga le nuove dimensioni ad entrambi i viewport
    public void resize(int width, int height)
    {
        // true = centra la camera (importante per FitViewport)
        mainStage.getViewport().update(width, height, true);
        uiStage.getViewport().update(width, height, true);
    }

    public void pause()   { }
    public void resume()  { }
    public void dispose() { }

    public void show()
    {
        InputMultiplexer im = (InputMultiplexer) Gdx.input.getInputProcessor();
        // BaseScreen prima: keyDown() viene intercettato prima di uiStage
        im.addProcessor(this);
        im.addProcessor(uiStage);
        im.addProcessor(mainStage);
    }

    public void hide()
    {
        InputMultiplexer im = (InputMultiplexer) Gdx.input.getInputProcessor();
        im.removeProcessor(this);
        im.removeProcessor(uiStage);
        im.removeProcessor(mainStage);
    }

    public boolean isTouchDownEvent(Event e)
    {
        return (e instanceof InputEvent) && ((InputEvent) e).getType().equals(Type.touchDown);
    }

    public boolean keyDown(int keycode)                              { return false; }
    public boolean keyUp(int keycode)                                { return false; }
    public boolean keyTyped(char c)                                  { return false; }
    public boolean mouseMoved(int x, int y)                         { return false; }
    public boolean scrolled(int amount)                              { return false; }
    public boolean touchDown(int x, int y, int pointer, int button) { return false; }
    public boolean touchDragged(int x, int y, int pointer)          { return false; }
    public boolean touchUp(int x, int y, int pointer, int button)   { return false; }
}

package pablo;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.Input;
import com.badlogic.gdx.audio.Music;
import com.badlogic.gdx.graphics.GL20;
import com.badlogic.gdx.graphics.Texture;
import com.badlogic.gdx.graphics.g2d.SpriteBatch;
import pablo.framework.BaseGame;
import pablo.framework.BaseScreen;

public class IntroScreen extends BaseScreen
{
    private SpriteBatch batch;
    private Texture currentFrame; // Solo 1 texture attiva alla volta
    private Music music;

    private boolean done = false;

    // Assicurati che totaleFrames corrisponda al numero esatto di file nella tua cartella (es. avevi 424 frame in precedenza)
    private int totalFrames = 424;
    private float fps = 30f;
    private float frameDuration = 1f / fps;
    private float elapsedTime = 0f;
    private int currentFrameIndex = -1;

    public void initialize()
    {
        batch = new SpriteBatch();

        music = Gdx.audio.newMusic(Gdx.files.internal("assets/Video/intro.mp3"));
        music.play();
    }

    @Override
    public void update(float dt) {
        // Accumuliamo il tempo passato usando il deltaTime di LibGDX (più affidabile di music.getPosition())
        elapsedTime += dt;
    }

    @Override
    public void render(float dt)
    {
        update(dt);
        if (music == null) return;

        if (Gdx.input.justTouched() || Gdx.input.isKeyJustPressed(Input.Keys.ANY_KEY)) {
            goToMenu();
            return;
        }

        // Calcoliamo a quale file / fotogramma corrispondiamo (partendo da 1 come i tuoi nomi file)
        int frameIndex = (int)(elapsedTime / frameDuration) + 1;

        if (frameIndex > totalFrames) {
            goToMenu();
            return;
        }

        // Se è avvenuto il momento di cambiare fotogramma...
        if (frameIndex != currentFrameIndex) {
            String path = String.format("assets/Video/frame_%04d.png", frameIndex);
            if (Gdx.files.internal(path).exists()) {
                Texture nextFrame = new Texture(Gdx.files.internal(path));
                if (currentFrame != null) {
                    currentFrame.dispose();
                }
                currentFrame = nextFrame;
                currentFrameIndex = frameIndex;
            }
        }

        Gdx.gl.glClearColor(0, 0, 0, 1);
        Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

        if (currentFrame != null) {
            float viewportWidth = mainStage.getViewport().getWorldWidth();
            float viewportHeight = mainStage.getViewport().getWorldHeight();
            batch.setProjectionMatrix(mainStage.getCamera().combined);
            batch.begin();
            batch.draw(currentFrame, 0, 0, viewportWidth, viewportHeight);
            batch.end();
        }
    }

    private void goToMenu()
    {
        if (done) return;
        done = true;

        if (music != null) {
            music.stop();
        }

        BaseGame.setActiveScreen(new MenuScreen());
    }

    @Override
    public void dispose()
    {
        if (batch != null) batch.dispose();

        // Liberiamo la singola immagine attuale dallo heap
        if (currentFrame != null) {
            currentFrame.dispose();
        }

        if (music != null) music.dispose();
    }
}

package pablo;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.Input;
import com.badlogic.gdx.audio.Music;
import com.badlogic.gdx.graphics.GL20;
