// Launcher.java

package pablo;

import com.badlogic.gdx.Game;
import com.badlogic.gdx.backends.lwjgl.LwjglApplication;
import com.badlogic.gdx.backends.lwjgl.LwjglApplicationConfiguration;

public class Launcher
{
    public static void main (String[] args)
    {
        LwjglApplicationConfiguration config = new LwjglApplicationConfiguration();
        config.title = "HollowKnight-Pablo";
        config.width = 1920;
        config.height = 1080;
        config.fullscreen = false;
        config.useHDPI = false;

        Game myGame = new PabloGame();
        new LwjglApplication(myGame, config);
    }
}

// Launcher.java

package pablo;

import com.badlogic.gdx.Game;
import com.badlogic.gdx.backends.lwjgl.LwjglApplication;
import com.badlogic.gdx.backends.lwjgl.LwjglApplicationConfiguration;

public class Launcher
{
    public static void main (String[] args)
    {
        LwjglApplicationConfiguration config = new LwjglApplicationConfiguration();
        config.title = "HollowKnight-Pablo";
        config.width = 800;
        config.height = 640;
        config.fullscreen = true;
        config.useHDPI = false;

        Game myGame = new PabloGame();
        new LwjglApplication(myGame, config);
    }
}

// PabloGame.java
package pablo;

import pablo.framework.BaseGame;

public class PabloGame extends BaseGame
{
    public void create()
    {
        super.create();
        GameSettings.get().setFullscreen(true);
        setActiveScreen( new IntroScreen() ); // era: new MenuScreen()
    }
}

// PabloGame.java
package pablo;

import pablo.framework.BaseGame;

public class PabloGame extends BaseGame
{
    public void create()
    {
        super.create();
        // Ora il fullscreen è già impostato dal Launcher
        setActiveScreen( new IntroScreen() );
    }
}
